#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
struct RuntimeNestedRenderCacheKey {
    host: u32,
    referenced_artboard_global: u32,
    instance_revision: u64,
}

const RUNTIME_COMPONENT_LIST_CACHE_NAMESPACE: u64 = 1_u64 << 63;

/// Renderer resources follow a mounted nested-artboard tree, where each
/// parent normally owns only a handful of direct children. C++ reaches those
/// resources through the already-mounted `NestedArtboard::m_Instance`
/// directly; using a tree map here added a logarithmic lookup and node walk to
/// every retained draw. Keep the external renderer-resource ownership needed
/// by Rust, but use the same small, parent-local shape as the mounted tree.
enum RuntimeNestedRenderCaches<T> {
    Flat(Vec<(RuntimeNestedRenderCacheKey, T)>),
    Ordered(BTreeMap<RuntimeNestedRenderCacheKey, T>),
}

impl<T> Default for RuntimeNestedRenderCaches<T> {
    fn default() -> Self {
        Self::Flat(Vec::new())
    }
}

impl<T> RuntimeNestedRenderCaches<T> {
    // Authored nesting can be wider than the usual handful of direct children:
    // ai_assitant has 16 under one artboard. C++ still reaches each child
    // through direct NestedArtboard ownership, so keep that real-world width
    // in the parent-local flat tier instead of spilling every draw to a map.
    const FLAT_CAPACITY: usize = 32;

    #[inline]
    fn get_or_insert_with(
        &mut self,
        key: RuntimeNestedRenderCacheKey,
        make: impl FnOnce() -> T,
    ) -> &mut T {
        if matches!(self, Self::Ordered(_)) {
            let Self::Ordered(entries) = self else {
                unreachable!();
            };
            return entries.entry(key).or_insert_with(make);
        }

        let existing = match self {
            Self::Flat(entries) => entries.iter().position(|(candidate, _)| *candidate == key),
            Self::Ordered(_) => unreachable!(),
        };
        if let Some(index) = existing {
            let Self::Flat(entries) = self else {
                unreachable!();
            };
            return &mut entries[index].1;
        }

        let should_spill = key.instance_revision & RUNTIME_COMPONENT_LIST_CACHE_NAMESPACE != 0
            || matches!(self, Self::Flat(entries) if entries.len() == Self::FLAT_CAPACITY);
        if should_spill {
            // Component-list rows are a potentially large collection, unlike
            // the mounted direct-child set. Preserve logarithmic lookup for
            // that explicit cache-key namespace, and for unusually broad
            // ordinary nesting trees.
            let Self::Flat(entries) = std::mem::replace(self, Self::Ordered(BTreeMap::new()))
            else {
                unreachable!();
            };
            let Self::Ordered(ordered) = self else {
                unreachable!();
            };
            ordered.extend(entries);
            return ordered.entry(key).or_insert_with(make);
        }

        let Self::Flat(entries) = self else {
            unreachable!();
        };
        entries.push((key, make()));
        &mut entries.last_mut().expect("just inserted").1
    }

    #[inline]
    fn get_or_insert_default(&mut self, key: RuntimeNestedRenderCacheKey) -> &mut T
    where
        T: Default,
    {
        self.get_or_insert_with(key, T::default)
    }
}

#[derive(Default)]
pub struct RuntimeRenderPaintCache {
    paints: RuntimeRenderPaints,
    paint_configurations: RuntimeRenderPaintConfigurationSlots,
    preparation_without_nested_layout: Option<RuntimePaintPreparationFrame>,
    preparation: Option<RuntimePaintPreparationFrame>,
    images: RuntimeRenderImages,
    meshes: RuntimeMeshRenderBufferSlots,
    nested_artboards: BTreeMap<RuntimeNestedRenderCacheKey, RuntimeRenderPaintCache>,
    // Nested layout hosts require C++'s deferred-gradient preparation pass.
    // This is a conservative file-level fact, so compute it once while the
    // instance paint cache is built instead of walking the retained tree on
    // every frame.
    requires_nested_layout_prepass: bool,
    // A flat artboard containing only solid paints has no paint work to do
    // between advance and draw. Keep this conservative: nested/component-list
    // hosts can materialize child caches during preparation, even when neither
    // the parent nor child contains a gradient.
    paint_preparation_is_noop: bool,
    // A file containing no gradient paints only needs the recursive paint
    // preparation walk when its mounted instance tree changes. SolidColor
    // updates are applied to retained paints during draw, just as C++ mutates
    // its attached RenderPaint directly in SolidColor::colorValueChanged.
    paint_preparation_is_solid_only_tree: bool,
    solid_only_tree_structure_epoch: Option<u64>,
    image_decode_error: Option<ImageDecodeError>,
}

#[derive(Default)]
pub struct RuntimeRenderPaints {
    paints_by_global: Vec<Option<Box<dyn RenderPaint>>>,
    text_paint_pools: RuntimeTextPaintPools,
}

#[derive(Default)]
struct RuntimeTextPaintPools {
    owner: Option<(u32, u64)>,
    by_text_local: Vec<BTreeMap<usize, Vec<Box<dyn RenderPaint>>>>,
}

impl RuntimeTextPaintPools {
    fn pool_mut(&mut self, key: RuntimeTextPaintPoolKey) -> &mut Vec<Box<dyn RenderPaint>> {
        let owner = (key.graph_global_id, key.instance_identity);
        if self.owner != Some(owner) {
            self.owner = Some(owner);
            self.by_text_local.clear();
        }
        if self.by_text_local.len() <= key.text_local {
            self.by_text_local
                .resize_with(key.text_local.saturating_add(1), BTreeMap::new);
        }
        self.by_text_local[key.text_local]
            .entry(key.style_local)
            .or_default()
    }

    fn pool(&self, key: RuntimeTextPaintPoolKey) -> Option<&Vec<Box<dyn RenderPaint>>> {
        if self.owner != Some((key.graph_global_id, key.instance_identity)) {
            return None;
        }
        self.by_text_local
            .get(key.text_local)?
            .get(&key.style_local)
    }
}

impl RuntimeRenderPaints {
    fn contains(&self, global_id: u32) -> bool {
        self.paints_by_global
            .get(global_id as usize)
            .is_some_and(Option::is_some)
    }

    fn insert(&mut self, global_id: u32, paint: Box<dyn RenderPaint>) {
        let slot = global_id as usize;
        if self.paints_by_global.len() <= slot {
            self.paints_by_global.resize_with(slot + 1, || None);
        }
        self.paints_by_global[slot] = Some(paint);
    }

    fn paint(&self, global_id: u32) -> Option<&Box<dyn RenderPaint>> {
        self.paints_by_global
            .get(global_id as usize)
            .and_then(|paint| paint.as_ref())
    }

    fn paint_mut(&mut self, global_id: u32) -> Option<&mut Box<dyn RenderPaint>> {
        self.paints_by_global.get_mut(global_id as usize)?.as_mut()
    }
}

impl RuntimeRenderPaintCache {
    /// Returns whether this retained cache has paint or slice resources that
    /// must be refreshed before its next draw.
    ///
    /// Solid colors update their retained render paints during draw, matching
    /// C++ `SolidColor::colorValueChanged`. A solid-only tree therefore only
    /// needs the recursive preparation pass on its first mounted structure and
    /// after that structure changes. Gradients stay conservative, and authored
    /// NSlicers always run their mesh preparation work.
    #[inline]
    pub fn needs_paint_preparation(
        &self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
    ) -> bool {
        if !graph.n_slicer_details.is_empty() {
            return true;
        }
        if self.paint_preparation_is_noop {
            return false;
        }
        if self.paint_preparation_is_solid_only_tree {
            let nested_structure_epoch = instance.nested_structure_epoch();
            return nested_structure_epoch.is_none()
                || self.solid_only_tree_structure_epoch != nested_structure_epoch;
        }
        true
    }

    /// Allocate one artboard-tree cache using host-provided bytes for image
    /// assets whose serialized file contents are absent.
    ///
    /// External bytes are keyed by the semantic `FileAsset.assetId`. They are
    /// decoded here, at cache allocation time, so callers can discard a failed
    /// candidate cache and retry. Serialized `FileAssetContents` always wins.
    pub fn preallocate_for_artboard_tree_with_external_images(
        runtime: &RuntimeFile,
        graph: &ArtboardGraph,
        artboards: &[ArtboardGraph],
        external_images: &BTreeMap<u32, Arc<[u8]>>,
        factory: &mut dyn RenderFactory,
        max_retained_decoded_image_bytes: Option<usize>,
    ) -> Self {
        preallocate_render_paint_cache_for_artboard_tree_internal(
            runtime,
            graph,
            artboards,
            Some(external_images),
            factory,
            false,
            true,
            false,
            None,
            max_retained_decoded_image_bytes,
        )
    }

    pub fn root_paints_mut(&mut self) -> &mut RuntimeRenderPaints {
        &mut self.paints
    }

    pub fn root_images_mut(&mut self) -> &mut RuntimeRenderImages {
        &mut self.images
    }

    pub fn image_decode_error(&self) -> Option<ImageDecodeError> {
        self.image_decode_error
    }
}

#[derive(Default)]
pub struct RuntimeRenderImages {
    // RF-14 backend sidecar: each dense slot is owned one-to-one by the
    // file's ImageAsset global id. It has no scene epoch or prepared-frame
    // lifetime and is shared by every Image referencer like C++
    // ImageAsset::m_RenderImage.
    images_by_global: Vec<Option<RuntimeRenderImageEntry>>,
    retained_decoded_bytes: usize,
    // `None` retains every decoded image, matching pinned C++, which has no
    // aggregate decoded-image ceiling. Bounded admission is a host import
    // policy chosen per cache by the high-level `nuxie::File` path; the
    // low-level compatibility/golden paths stay unbounded.
    max_retained_decoded_bytes: Option<usize>,
}

struct RuntimeRenderImageEntry {
    image: Box<dyn RenderImage>,
    decoded_byte_length: usize,
}

impl RuntimeRenderImages {
    /// An image cache whose aggregate decoded-byte admission follows the
    /// caller's import policy. Compressed assets can be tiny while their
    /// canonical RGBA textures are large, so the encoded FileAsset budget
    /// cannot substitute for this post-header, pre-decode reservation.
    pub fn with_max_retained_decoded_bytes(max_retained_decoded_bytes: Option<usize>) -> Self {
        Self {
            max_retained_decoded_bytes,
            ..Self::default()
        }
    }

    pub fn get(&self, global_id: u32) -> Option<&dyn RenderImage> {
        self.images_by_global
            .get(global_id as usize)
            .and_then(|entry| entry.as_ref())
            .map(|entry| entry.image.as_ref())
    }

    pub fn insert(&mut self, global_id: u32, image: Box<dyn RenderImage>) {
        let Some(decoded_byte_length) = decoded_rgba_len(image.width(), image.height()) else {
            return;
        };
        if self
            .try_reserve_replacement_decoded_bytes(global_id, decoded_byte_length)
            .is_none()
        {
            return;
        }
        self.insert_reserved(global_id, image, decoded_byte_length);
    }

    fn try_reserve_replacement_decoded_bytes(
        &mut self,
        global_id: u32,
        decoded_byte_length: usize,
    ) -> Option<usize> {
        let replaced_decoded_byte_length = self
            .images_by_global
            .get(global_id as usize)
            .and_then(|entry| entry.as_ref())
            .map_or(0, |entry| entry.decoded_byte_length);
        let next_retained_decoded_bytes = self
            .retained_decoded_bytes
            .checked_sub(replaced_decoded_byte_length)?
            .checked_add(decoded_byte_length)?;
        if self
            .max_retained_decoded_bytes
            .is_some_and(|budget| next_retained_decoded_bytes > budget)
        {
            return None;
        }
        let previous_retained_decoded_bytes = self.retained_decoded_bytes;
        self.retained_decoded_bytes = next_retained_decoded_bytes;
        Some(previous_retained_decoded_bytes)
    }

    fn cancel_decoded_byte_reservation(&mut self, previous_retained_decoded_bytes: usize) {
        self.retained_decoded_bytes = previous_retained_decoded_bytes;
    }

    fn insert_reserved(
        &mut self,
        global_id: u32,
        image: Box<dyn RenderImage>,
        decoded_byte_length: usize,
    ) {
        let slot = global_id as usize;
        if self.images_by_global.len() <= slot {
            self.images_by_global.resize_with(slot + 1, || None);
        }
        self.images_by_global[slot] = Some(RuntimeRenderImageEntry {
            image,
            decoded_byte_length,
        });
    }

    fn dimensions(&self) -> impl Iterator<Item = (u32, u32, u32, usize)> + '_ {
        self.images_by_global
            .iter()
            .enumerate()
            .filter_map(|(global_id, entry)| {
                let global_id = u32::try_from(global_id).ok()?;
                let image = entry.as_ref()?.image.as_ref();
                Some((
                    global_id,
                    image.width(),
                    image.height(),
                    runtime_render_image_identity(image),
                ))
            })
    }
}

fn runtime_render_image_identity(image: &dyn RenderImage) -> usize {
    (image as *const dyn RenderImage as *const ()) as usize
}

#[derive(Debug, Clone, PartialEq)]
struct RuntimeCachedRenderPaintConfiguration {
    instance_epoch: u128,
    configuration: RuntimeRenderPaintConfiguration,
}

#[derive(Default)]
struct RuntimeRenderPaintConfigurationSlots {
    by_global: Vec<Option<RuntimeCachedRenderPaintConfiguration>>,
}

impl RuntimeRenderPaintConfigurationSlots {
    fn get(&self, paint_global_id: u32) -> Option<&RuntimeCachedRenderPaintConfiguration> {
        self.by_global
            .get(paint_global_id as usize)
            .and_then(|configuration| configuration.as_ref())
    }

    fn is_current(&self, paint_global_id: u32, instance_epoch: u128) -> bool {
        self.get(paint_global_id)
            .is_some_and(|configuration| configuration.instance_epoch == instance_epoch)
    }

    fn get_mut(
        &mut self,
        paint_global_id: u32,
    ) -> Option<&mut RuntimeCachedRenderPaintConfiguration> {
        self.by_global.get_mut(paint_global_id as usize)?.as_mut()
    }

    fn insert(
        &mut self,
        paint_global_id: u32,
        configuration: RuntimeCachedRenderPaintConfiguration,
    ) {
        let slot = paint_global_id as usize;
        if self.by_global.len() <= slot {
            self.by_global.resize_with(slot + 1, || None);
        }
        self.by_global[slot] = Some(configuration);
    }

    fn remove(&mut self, paint_global_id: u32) {
        if let Some(configuration) = self.by_global.get_mut(paint_global_id as usize) {
            *configuration = None;
        }
    }
}

