    fn prepared_artboard_frame(
        &mut self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        runtime: Option<&RuntimeFile>,
    ) -> Arc<RuntimePreparedArtboardFrame> {
        let (mounted_component_list_layout_revision, mounted_component_list_prepared_revision) =
            runtime_mounted_component_list_revisions(instance);
        let world_dependent = self
            .prepared_artboard
            .as_ref()
            .filter(|frame| frame.key.graph_global_id == graph.global_id)
            .map(|frame| frame.world_dependent)
            .unwrap_or_else(|| runtime_command_frame_requires_world_epoch(graph));
        let key = RuntimePreparedArtboardCacheKey {
            graph_global_id: graph.global_id,
            command_epoch: instance.command_epoch(),
            world_epoch: world_dependent
                .then(|| instance.prepared_epoch())
                .unwrap_or_default(),
            mounted_component_list_layout_revision,
            mounted_component_list_prepared_revision,
        };
        if self
            .prepared_artboard
            .as_ref()
            .is_none_or(|frame| frame.key != key)
        {
            // The frame is only retained by this cache between calls.  When
            // no reader has kept a temporary Arc alive, recover the command
            // vector's allocation for this rebuild.  A held reader simply
            // takes the established fresh-vector path.
            let reusable_commands = self
                .prepared_artboard
                .take()
                .and_then(Arc::into_inner)
                .and_then(|frame| Arc::into_inner(frame.commands))
                .unwrap_or_default();
            let layout_frame = self.layout_bounds_frame(
                instance,
                graph,
                runtime,
                mounted_component_list_layout_revision,
            );
            let layout_bounds = layout_frame.bounds.clone();
            // Retain invisible drawables so the prepared stream's topology is
            // stable across opacity writes; replay applies the live willDraw.
            let commands = instance.draw_commands_with_live_drawable_order_reusing(
                graph,
                layout_bounds.as_ref().as_ref(),
                self,
                true,
                reusable_commands,
            );
            let component_list_layout_children = Arc::new(runtime_component_list_layout_children(
                instance,
                layout_frame.component_list_item_bounds.as_ref(),
            ));
            self.prepared_artboard = Some(Arc::new(RuntimePreparedArtboardFrame {
                key,
                world_dependent,
                layout_bounds,
                component_list_item_bounds: layout_frame.component_list_item_bounds,
                component_list_layout_children,
                commands: Arc::new(commands),
            }));
        }

        self.prepared_artboard
            .as_ref()
            .expect("prepared artboard frame was just populated")
            .clone()
    }

    fn retained_geometry_artboard_frame(
        &mut self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        runtime: &RuntimeFile,
    ) -> Arc<RuntimePreparedArtboardFrame> {
        // The prepared frame deliberately retains every drawable's command
        // topology across opacity writes. Geometry can therefore read
        // the same immutable frame and decide effective visibility at query
        // time without maintaining a second, divergent command cache.
        self.prepared_artboard_frame(instance, graph, Some(runtime))
    }

    fn layout_bounds_frame(
        &mut self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        runtime: Option<&RuntimeFile>,
        mounted_component_list_layout_revision: u64,
    ) -> RuntimeLayoutBoundsFrame {
        let key = RuntimeLayoutBoundsCacheKey {
            graph_global_id: graph.global_id,
            layout_epoch: instance.layout_epoch(),
            mounted_component_list_layout_revision,
        };
        if self
            .layout_bounds
            .as_ref()
            .is_none_or(|frame| frame.key != key)
        {
            let layout = TaffyRuntimeLayoutEngine.compute_layout(instance, graph, runtime);
            let (bounds, component_list_item_bounds) = match layout {
                Some(layout) => (Some(layout.bounds), layout.component_list_item_bounds),
                None => (None, BTreeMap::new()),
            };
            self.layout_bounds = Some(RuntimeLayoutBoundsFrame {
                key,
                bounds: Arc::new(bounds),
                component_list_item_bounds: Arc::new(component_list_item_bounds),
            });
        }

        self.layout_bounds
            .as_ref()
            .expect("layout bounds frame was just populated")
            .clone()
    }

    fn path_composer_lookup_frame(
        &mut self,
        graph: &ArtboardGraph,
    ) -> RuntimePathComposerLookupFrame {
        let key = RuntimePathComposerLookupCacheKey {
            graph_global_id: graph.global_id,
            graph_identity: graph as *const ArtboardGraph as usize,
        };
        if self
            .path_composer_lookup
            .as_ref()
            .is_none_or(|frame| frame.key != key)
        {
            self.path_composer_lookup = Some(RuntimePathComposerLookupFrame {
                key,
                path_index_by_local: Arc::new(runtime_local_index_lookup(
                    graph
                        .paths
                        .iter()
                        .enumerate()
                        .map(|(index, path)| (path.local_id, index)),
                )),
            });
        }

        self.path_composer_lookup
            .as_ref()
            .expect("path composer lookup frame was just populated")
            .clone()
    }

    fn path_geometry_commands_frame(
        &mut self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        path: &PathGeometryNode,
        layout_bounds: Option<&BTreeMap<usize, RuntimeLayoutBounds>>,
    ) -> RuntimeCachedPathGeometryCommands {
        let key = RuntimePathGeometryCommandsCacheKey {
            path_epoch: instance.path_epoch(),
            layout_epoch: instance.layout_epoch(),
        };
        let slot = self
            .path_geometry_commands
            .slot_mut(graph.global_id, path.local_id);

        if slot.as_ref().is_none_or(|cached| cached.key != key) {
            let runtime_path =
                instance.runtime_path_geometry_with_layout_control(path, layout_bounds);
            let weighted_context =
                instance.runtime_weighted_path_context(&runtime_path, graph, layout_bounds);
            let commands = path_commands(
                &runtime_path,
                ShapePaintPathKind::World,
                Mat2D::IDENTITY,
                weighted_context.as_ref(),
            );
            *slot = Some(RuntimeCachedPathGeometryCommands {
                key,
                path: Arc::new(runtime_path),
                commands: Arc::new(commands),
                has_weighted_context: weighted_context.is_some(),
            });
        }

        slot.as_ref()
            .expect("path geometry command cache was just populated")
            .clone()
    }

    fn gradient_preparation_frame(
        &mut self,
        graph: &ArtboardGraph,
    ) -> RuntimeGradientPreparationFrame {
        self.ensure_gradient_preparation_frame(graph).clone()
    }

    fn gradient_preparation_has_world_space_paints(&mut self, graph: &ArtboardGraph) -> bool {
        self.ensure_gradient_preparation_frame(graph)
            .has_world_space_gradient_paints
    }

    fn ensure_gradient_preparation_frame(
        &mut self,
        graph: &ArtboardGraph,
    ) -> &RuntimeGradientPreparationFrame {
        let key = RuntimeGradientPreparationCacheKey {
            graph_global_id: graph.global_id,
            graph_identity: graph as *const ArtboardGraph as usize,
        };
        if self
            .gradient_preparation
            .as_ref()
            .is_none_or(|frame| frame.key != key)
        {
            let paints_by_mutator = runtime_gradient_paints_by_mutator(graph);
            let has_world_space_gradient_paints =
                runtime_gradient_paints_include_world_space(graph, &paints_by_mutator);
            self.gradient_preparation = Some(RuntimeGradientPreparationFrame {
                key,
                paints_by_mutator: Arc::new(paints_by_mutator),
                dependency_order: Arc::new(runtime_gradient_dependency_order(
                    &graph.dependency_order,
                    graph,
                )),
                dependency_insertion_order: Arc::new(runtime_gradient_dependency_order(
                    if graph.dependency_insertion_order.is_empty() {
                        &graph.dependency_order
                    } else {
                        &graph.dependency_insertion_order
                    },
                    graph,
                )),
                has_world_space_gradient_paints,
            });
        }

        self.gradient_preparation
            .as_ref()
            .expect("gradient preparation frame was just populated")
    }

    fn retained_render_path_key(
        &self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        fill_rule: RenderFillRule,
    ) -> RuntimeRetainedRenderPathCacheKey {
        RuntimeRetainedRenderPathCacheKey {
            graph_global_id: graph.global_id,
            path_epoch: instance.path_epoch(),
            layout_epoch: instance.layout_epoch(),
            world_epoch: 0,
            fill_rule,
        }
    }

    fn retained_world_render_path_key(
        &self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        fill_rule: RenderFillRule,
    ) -> RuntimeRetainedRenderPathCacheKey {
        RuntimeRetainedRenderPathCacheKey {
            world_epoch: instance.prepared_epoch(),
            ..self.retained_render_path_key(instance, graph, fill_rule)
        }
    }

    fn clipping_shape_path_commands(
        &mut self,
        instance: &ArtboardInstance,
        graph: &ArtboardGraph,
        clipping_shape: &ClippingShapeNode,
        layout_bounds: Option<&BTreeMap<usize, RuntimeLayoutBounds>>,
    ) -> Arc<Vec<RuntimePathCommand>> {
        let key = RuntimeClippingShapeCommandsCacheKey {
            path_epoch: instance.path_epoch(),
            layout_epoch: instance.layout_epoch(),
            world_epoch: instance.prepared_epoch(),
        };
        if let Some(commands) =
            self.clipping_shape_commands
                .get(graph.global_id, clipping_shape.local_id, key)
        {
            return commands;
        }

        let commands = Arc::new(instance.runtime_clipping_shape_path_commands_uncached(
            clipping_shape,
            graph,
            layout_bounds,
            self,
        ));
        self.clipping_shape_commands.insert(
            graph.global_id,
            clipping_shape.local_id,
            key,
            commands.clone(),
        );
        commands
    }

