    #[derive(Default)]
    struct CountingStats {
        make_empty_paths: Cell<usize>,
        rewinds: Cell<usize>,
        add_raw_paths: Cell<usize>,
        fill_rules: Cell<usize>,
        lines: Cell<usize>,
        closes: Cell<usize>,
        linear_gradients: RefCell<Vec<[f32; 4]>>,
        linear_gradient_colors: RefCell<Vec<Vec<ColorInt>>>,
        image_decode_attempts: Cell<usize>,
        image_decode_failures_remaining: Cell<usize>,
    }

    struct CountingFactory {
        stats: Rc<CountingStats>,
        next_path_id: usize,
    }

    struct RecordingRenderer {
        ops: Rc<RefCell<Vec<String>>>,
    }

    #[derive(Default)]
    struct PathGeometryRecordingRenderer {
        draw_paths: Vec<Vec<(f32, f32)>>,
        clip_paths: Vec<Vec<(f32, f32)>>,
        clip_fill_rules: Vec<RenderFillRule>,
    }

    impl PathGeometryRecordingRenderer {
        fn path_points(path: &dyn RenderPath) -> Vec<(f32, f32)> {
            path.as_any()
                .downcast_ref::<CountingRenderPath>()
                .expect("counting render path")
                .raw_path
                .points()
                .iter()
                .map(|point| (point.x, point.y))
                .collect()
        }
    }

    impl Renderer for PathGeometryRecordingRenderer {
        fn save(&mut self) {}

        fn restore(&mut self) {}

        fn transform(&mut self, _transform: RenderMat2D) {}

        fn draw_path(&mut self, path: &dyn RenderPath, _paint: &dyn RenderPaint) {
            self.draw_paths.push(Self::path_points(path));
        }

        fn clip_path(&mut self, path: &dyn RenderPath) {
            self.clip_paths.push(Self::path_points(path));
            self.clip_fill_rules.push(
                path.as_any()
                    .downcast_ref::<CountingRenderPath>()
                    .expect("counting render path")
                    .fill_rule,
            );
        }

        fn draw_image(
            &mut self,
            _image: Option<&dyn RenderImage>,
            _sampler: RenderImageSampler,
            _blend_mode: RenderBlendMode,
            _opacity: f32,
        ) {
        }

        fn draw_image_mesh(
            &mut self,
            _image: Option<&dyn RenderImage>,
            _sampler: RenderImageSampler,
            _vertices: Option<&dyn RenderBuffer>,
            _uv_coords: Option<&dyn RenderBuffer>,
            _indices: Option<&dyn RenderBuffer>,
            _vertex_count: u32,
            _index_count: u32,
            _blend_mode: RenderBlendMode,
            _opacity: f32,
        ) {
        }

        fn modulate_opacity(&mut self, _opacity: f32) {}
    }

    fn assert_path_points_translated(
        baseline: &[(f32, f32)],
        moved: &[(f32, f32)],
        translate_x: f32,
        translate_y: f32,
    ) {
        assert_eq!(moved.len(), baseline.len(), "path point count changed");
        for (baseline, moved) in baseline.iter().zip(moved) {
            assert!(
                (moved.0 - (baseline.0 + translate_x)).abs() <= 0.0001
                    && (moved.1 - (baseline.1 + translate_y)).abs() <= 0.0001,
                "path point did not move with its transform: {baseline:?} -> {moved:?}"
            );
        }
    }

    impl Renderer for RecordingRenderer {
        fn save(&mut self) {
            self.ops.borrow_mut().push("save".to_owned());
        }

        fn restore(&mut self) {
            self.ops.borrow_mut().push("restore".to_owned());
        }

        fn transform(&mut self, transform: RenderMat2D) {
            self.ops
                .borrow_mut()
                .push(format!("transform:{:?}", transform.0));
        }

        fn draw_path(&mut self, _path: &dyn RenderPath, _paint: &dyn RenderPaint) {
            self.ops.borrow_mut().push("draw_path".to_owned());
        }

        fn clip_path(&mut self, _path: &dyn RenderPath) {
            self.ops.borrow_mut().push("clip_path".to_owned());
        }

        fn draw_image(
            &mut self,
            _image: Option<&dyn RenderImage>,
            _sampler: RenderImageSampler,
            _blend_mode: RenderBlendMode,
            _opacity: f32,
        ) {
            self.ops.borrow_mut().push("draw_image".to_owned());
        }

        fn draw_image_mesh(
            &mut self,
            _image: Option<&dyn RenderImage>,
            _sampler: RenderImageSampler,
            _vertices: Option<&dyn RenderBuffer>,
            _uv_coords: Option<&dyn RenderBuffer>,
            _indices: Option<&dyn RenderBuffer>,
            _vertex_count: u32,
            _index_count: u32,
            _blend_mode: RenderBlendMode,
            _opacity: f32,
        ) {
            self.ops.borrow_mut().push("draw_image_mesh".to_owned());
        }

        fn modulate_opacity(&mut self, opacity: f32) {
            self.ops.borrow_mut().push(format!("opacity:{opacity}"));
        }
    }

    struct FakeScriptInstance {
        ops: Rc<RefCell<Vec<String>>>,
        fails: bool,
    }

    impl ScriptInstance for FakeScriptInstance {
        fn has_method(&self, _method: ScriptMethod) -> Result<bool, ScriptError> {
            Ok(true)
        }

        fn call_method(
            &mut self,
            _method: ScriptMethod,
            _args: &[ScriptValue],
            _host: &mut dyn ScriptHost,
        ) -> Result<ScriptValue, ScriptError> {
            Ok(ScriptValue::Nil)
        }

        fn call_draw(
            &mut self,
            _factory: &mut dyn RenderFactory,
            _renderer: &mut dyn Renderer,
            _host: &mut dyn ScriptHost,
        ) -> Result<(), ScriptError> {
            self.ops.borrow_mut().push("script_draw".to_owned());
            if self.fails {
                Err(ScriptError::new("intentional draw failure"))
            } else {
                Ok(())
            }
        }

        fn get_input(&self, _name: &str) -> Result<ScriptValue, ScriptError> {
            Ok(ScriptValue::Nil)
        }

        fn set_input(&mut self, _name: &str, _value: ScriptValue) -> Result<(), ScriptError> {
            Ok(())
        }
    }

    struct CountingRenderPath {
        stats: Rc<CountingStats>,
        id: usize,
        raw_path: RawPath,
        fill_rule: RenderFillRule,
    }

    impl RenderPath for CountingRenderPath {
        fn as_any(&self) -> &dyn Any {
            self
        }

        fn rewind(&mut self) {
            self.stats.rewinds.set(self.stats.rewinds.get() + 1);
            self.raw_path.rewind();
        }

        fn fill_rule(&mut self, value: RenderFillRule) {
            self.stats.fill_rules.set(self.stats.fill_rules.get() + 1);
            self.fill_rule = value;
        }

        fn add_render_path(&mut self, _path: &dyn RenderPath, _transform: RenderMat2D) {}

        fn add_render_path_backwards(&mut self, _path: &dyn RenderPath, _transform: RenderMat2D) {}

        fn add_raw_path(&mut self, path: &RawPath) {
            self.stats
                .add_raw_paths
                .set(self.stats.add_raw_paths.get() + 1);
            self.raw_path.add_path(path, RenderMat2D::IDENTITY);
        }

        fn move_to(&mut self, x: f32, y: f32) {
            self.raw_path.move_to(x, y);
        }

        fn line_to(&mut self, x: f32, y: f32) {
            self.stats.lines.set(self.stats.lines.get() + 1);
            self.raw_path.line_to(x, y);
        }

        fn cubic_to(&mut self, ox: f32, oy: f32, ix: f32, iy: f32, x: f32, y: f32) {
            self.raw_path.cubic_to(ox, oy, ix, iy, x, y);
        }

        fn close(&mut self) {
            self.stats.closes.set(self.stats.closes.get() + 1);
            self.raw_path.close();
        }
    }

    struct TestRenderBuffer {
        buffer_type: RenderBufferType,
        flags: RenderBufferFlags,
        bytes: Vec<u8>,
    }

    impl RenderBuffer for TestRenderBuffer {
        fn as_any(&self) -> &dyn Any {
            self
        }

        fn buffer_type(&self) -> RenderBufferType {
            self.buffer_type
        }

        fn flags(&self) -> RenderBufferFlags {
            self.flags
        }

        fn size_in_bytes(&self) -> usize {
            self.bytes.len()
        }

        fn map_mut(&mut self) -> &mut [u8] {
            &mut self.bytes
        }

        fn unmap(&mut self) {}
    }

    struct TestRenderShader;

    impl RenderShader for TestRenderShader {
        fn as_any(&self) -> &dyn Any {
            self
        }
    }

    struct TestRenderImage;

    impl RenderImage for TestRenderImage {
        fn as_any(&self) -> &dyn Any {
            self
        }

        fn width(&self) -> u32 {
            0
        }

        fn height(&self) -> u32 {
            0
        }
    }

    struct SizedTestRenderImage {
        width: u32,
        height: u32,
    }

    impl RenderImage for SizedTestRenderImage {
        fn as_any(&self) -> &dyn Any {
            self
        }

        fn width(&self) -> u32 {
            self.width
        }

        fn height(&self) -> u32 {
            self.height
        }
    }

    struct TestRenderPaint;

    impl RenderPaint for TestRenderPaint {
        fn as_any(&self) -> &dyn Any {
            self
        }

        fn style(&mut self, _style: RenderPaintStyle) {}
        fn color(&mut self, _value: ColorInt) {}
        fn thickness(&mut self, _value: f32) {}
        fn join(&mut self, _value: RenderStrokeJoin) {}
        fn cap(&mut self, _value: RenderStrokeCap) {}
        fn feather(&mut self, _value: f32) {}
        fn blend_mode(&mut self, _value: RenderBlendMode) {}
        fn shader(&mut self, _shader: Option<&dyn RenderShader>) {}
        fn invalidate_stroke(&mut self) {}
    }

    impl RenderFactory for CountingFactory {
        fn make_render_buffer(
            &mut self,
            buffer_type: RenderBufferType,
            flags: RenderBufferFlags,
            size_in_bytes: usize,
        ) -> Box<dyn RenderBuffer> {
            Box::new(TestRenderBuffer {
                buffer_type,
                flags,
                bytes: vec![0; size_in_bytes],
            })
        }

        fn make_linear_gradient(
            &mut self,
            sx: f32,
            sy: f32,
            ex: f32,
            ey: f32,
            colors: &[ColorInt],
            _stops: &[f32],
        ) -> Box<dyn RenderShader> {
            self.stats
                .linear_gradients
                .borrow_mut()
                .push([sx, sy, ex, ey]);
            self.stats
                .linear_gradient_colors
                .borrow_mut()
                .push(colors.to_vec());
            Box::new(TestRenderShader)
        }

        fn make_radial_gradient(
            &mut self,
            _cx: f32,
            _cy: f32,
            _radius: f32,
            _colors: &[ColorInt],
            _stops: &[f32],
        ) -> Box<dyn RenderShader> {
            Box::new(TestRenderShader)
        }

        fn make_render_path(
            &mut self,
            raw_path: RawPath,
            fill_rule: RenderFillRule,
        ) -> Box<dyn RenderPath> {
            let id = self.next_path_id;
            self.next_path_id += 1;
            Box::new(CountingRenderPath {
                stats: Rc::clone(&self.stats),
                id,
                raw_path,
                fill_rule,
            })
        }

        fn make_empty_render_path(&mut self) -> Box<dyn RenderPath> {
            self.stats
                .make_empty_paths
                .set(self.stats.make_empty_paths.get() + 1);
            self.make_render_path(RawPath::new(), RenderFillRule::NonZero)
        }

        fn make_render_paint(&mut self) -> Box<dyn RenderPaint> {
            Box::new(TestRenderPaint)
        }

        fn decode_image(
            &mut self,
            _data: &[u8],
        ) -> std::result::Result<Box<dyn RenderImage>, ImageDecodeError> {
            self.stats
                .image_decode_attempts
                .set(self.stats.image_decode_attempts.get() + 1);
            let failures_remaining = self.stats.image_decode_failures_remaining.get();
            if failures_remaining != 0 {
                self.stats
                    .image_decode_failures_remaining
                    .set(failures_remaining - 1);
                return Err(ImageDecodeError);
            }
            Ok(Box::new(TestRenderImage))
        }
    }

    fn compressed_rgba_png(width: u32, height: u32) -> Vec<u8> {
        let decoded_byte_length = decoded_rgba_len(width, height).expect("test image is bounded");
        let mut encoded = Vec::new();
        {
            let mut encoder = png::Encoder::new(&mut encoded, width, height);
            encoder.set_color(png::ColorType::Rgba);
            encoder.set_depth(png::BitDepth::Eight);
            let mut writer = encoder.write_header().expect("PNG header encodes");
            writer
                .write_image_data(&vec![0; decoded_byte_length])
                .expect("PNG pixels encode");
        }
        encoded
    }

    // The bounded host import policy exercised by these admission tests; the
    // high-level `nuxie::File` default in `FileImportLimits`.
    const HOST_BOUNDED_DECODED_IMAGE_BYTES: usize = 64 * 1024 * 1024;

    #[test]
    fn retained_images_reserve_one_aggregate_decoded_budget_before_decode() {
        const WIDTH: u32 = 4_096;
        const HEIGHT: u32 = 2_048;

        let encoded = compressed_rgba_png(WIDTH, HEIGHT);
        assert_eq!(
            nuxie_image_codec::validate_encoded_image(&encoded),
            Some(nuxie_image_codec::DecodedImageDimensions {
                width: WIDTH,
                height: HEIGHT,
            }),
            "the compressed regression payload must be fully valid"
        );
        let file = RuntimeFile::from_authoring_records(vec![
            authoring_record("Backboard", Vec::new()),
            authoring_record(
                "ImageAsset",
                vec![authoring_property(
                    "ImageAsset",
                    "assetId",
                    AuthoringValue::Uint(10),
                )],
            ),
            authoring_record(
                "FileAssetContents",
                vec![authoring_property(
                    "FileAssetContents",
                    "bytes",
                    AuthoringValue::Bytes(encoded.clone()),
                )],
            ),
            authoring_record(
                "ImageAsset",
                vec![authoring_property(
                    "ImageAsset",
                    "assetId",
                    AuthoringValue::Uint(11),
                )],
            ),
            authoring_record(
                "ImageAsset",
                vec![authoring_property(
                    "ImageAsset",
                    "assetId",
                    AuthoringValue::Uint(12),
                )],
            ),
            authoring_record("Artboard", Vec::new()),
        ])
        .expect("mixed embedded/external image fixture imports");
        let image_globals = file
            .file_assets()
            .into_iter()
            .filter(|asset| asset.type_name == "ImageAsset")
            .map(|asset| asset.id)
            .collect::<Vec<_>>();
        let image_assets = RuntimeImageAssetCatalog::from_runtime(&file);
        assert_eq!(image_globals.len(), 3);
        let external_images = BTreeMap::from([
            (11, Arc::<[u8]>::from(encoded.clone())),
            (12, Arc::<[u8]>::from(encoded)),
        ]);
        let stats = Rc::new(CountingStats::default());
        stats.image_decode_failures_remaining.set(1);
        let mut factory = CountingFactory {
            stats: Rc::clone(&stats),
            next_path_id: 0,
        };
        let mut images = RuntimeRenderImages::with_max_retained_decoded_bytes(Some(
            HOST_BOUNDED_DECODED_IMAGE_BYTES,
        ));

        assert_eq!(
            predecode_render_image(
                &file,
                &image_assets,
                image_globals[0],
                Some(&external_images),
                &mut factory,
                &mut images,
            ),
            Err(ImageDecodeError),
            "a codec failure propagates"
        );
        assert_eq!(images.retained_decoded_bytes, 0, "failed decode rolls back");
        predecode_render_image(
            &file,
            &image_assets,
            image_globals[0],
            Some(&external_images),
            &mut factory,
            &mut images,
        )
        .expect("embedded image retry decodes");
        predecode_render_image(
            &file,
            &image_assets,
            image_globals[1],
            Some(&external_images),
            &mut factory,
            &mut images,
        )
        .expect("external image fills the remaining budget");
        assert_eq!(
            images.retained_decoded_bytes,
            HOST_BOUNDED_DECODED_IMAGE_BYTES
        );
        assert_eq!(
            predecode_render_image(
                &file,
                &image_assets,
                image_globals[2],
                Some(&external_images),
                &mut factory,
                &mut images,
            ),
            Err(ImageDecodeError),
            "the third individually valid compressed image exceeds the aggregate budget"
        );
        assert_eq!(
            stats.image_decode_attempts.get(),
            3,
            "aggregate admission rejects before invoking the decoder"
        );
        assert!(images.get(image_globals[0]).is_some());
        assert!(images.get(image_globals[1]).is_some());
        assert!(images.get(image_globals[2]).is_none());
    }

    #[test]
    fn retained_image_replacement_admits_net_size_and_rejects_atomically() {
        const HALF_BUDGET_WIDTH: u32 = 4_096;
        const HALF_BUDGET_HEIGHT: u32 = 2_048;

        let mut images = RuntimeRenderImages::with_max_retained_decoded_bytes(Some(
            HOST_BOUNDED_DECODED_IMAGE_BYTES,
        ));
        for global_id in [7, 8] {
            images.insert(
                global_id,
                Box::new(SizedTestRenderImage {
                    width: HALF_BUDGET_WIDTH,
                    height: HALF_BUDGET_HEIGHT,
                }),
            );
        }
        assert_eq!(
            images.retained_decoded_bytes, HOST_BOUNDED_DECODED_IMAGE_BYTES,
            "two half-budget images fill the aggregate exactly",
        );

        images.insert(
            7,
            Box::new(SizedTestRenderImage {
                width: 1,
                height: 1,
            }),
        );
        let replacement = images.get(7).expect("smaller replacement is retained");
        assert_eq!((replacement.width(), replacement.height()), (1, 1));
        let retained_after_replacement = decoded_rgba_len(HALF_BUDGET_WIDTH, HALF_BUDGET_HEIGHT)
            .expect("half-budget dimensions are valid")
            .checked_add(decoded_rgba_len(1, 1).expect("one pixel is valid"))
            .expect("test dimensions fit usize");
        assert_eq!(images.retained_decoded_bytes, retained_after_replacement);

        images.insert(
            7,
            Box::new(SizedTestRenderImage {
                width: 4_096,
                height: 3_072,
            }),
        );
        let retained = images
            .get(7)
            .expect("a rejected replacement preserves the current image");
        assert_eq!(
            (retained.width(), retained.height()),
            (1, 1),
            "the other half-budget image plus a 48 MiB replacement exceeds the aggregate",
        );
        assert_eq!(
            images.retained_decoded_bytes, retained_after_replacement,
            "a rejected replacement must not mutate aggregate accounting",
        );
    }

    #[test]
    fn retained_images_without_budget_admit_past_the_bounded_host_policy() {
        const HALF_BUDGET_WIDTH: u32 = 4_096;
        const HALF_BUDGET_HEIGHT: u32 = 2_048;

        let mut images = RuntimeRenderImages::default();
        for global_id in [7, 8, 9] {
            images.insert(
                global_id,
                Box::new(SizedTestRenderImage {
                    width: HALF_BUDGET_WIDTH,
                    height: HALF_BUDGET_HEIGHT,
                }),
            );
        }
        for global_id in [7, 8, 9] {
            assert!(
                images.get(global_id).is_some(),
                "the unbounded compatibility path retains every image, like C++",
            );
        }
        assert!(images.retained_decoded_bytes > HOST_BOUNDED_DECODED_IMAGE_BYTES);
    }

